import type {IListItem, ITreeItem} from "@lmb-it/kitsconcerto-types";

// ✅ Platform-Agnostic Tree Definition
// This matches PrimeReact's shape but doesn't require the library to be installed.
export interface ITreeNode {
  key?: string | number;
  label?: string;
  data?: any;
  icon?: string;
  children?: ITreeNode[];
  style?: any;
  className?: string;
  selectable?: boolean;
  leaf?: boolean;
}

/**
 * 0: Empty, 1: Groups, 2: Strings, 3: Numbers, 4: Objects, 5: Mixed
 */
export const arrayType = (arr: any): number => {
  if (!Array.isArray(arr) || arr.length === 0) return 0;

  const first = arr[0];
  if (Array.isArray(first)) return 1;

  if (arr.every((i) => typeof i === "string")) return 2;
  if (arr.every((i) => typeof i === "number")) return 3;

  if (arr.every((i) => typeof i === "object" && !Array.isArray(i) && i !== null)) {
    return 4;
  }

  return 5;
};

export const checkKeys = (
    list: any[],
    labelKey: string,
    valueKey: string | undefined,
) => {
  if (
      list.length > 0 &&
      typeof list[0] === "object" &&
      !Array.isArray(list[0]) &&
      list[0] !== null
  ) {
    if (!(labelKey in list[0])) {
      // Strict check: if key is missing and it's not the default "label"
      if (labelKey !== "label") throw Error(`Label Key "${labelKey}" missing in list.`);
    }

    if (valueKey && !(valueKey in list[0])) {
      if (valueKey !== "value") throw Error(`Value Key "${valueKey}" missing in list.`);
    }
  }
};

/**
 * Recursively maps arrays (implicit groups) into explicit Group objects.
 */
export const reMapping = (
    arr: any[],
    level: number = 0,
    labelKey: string,
    valueKey: string,
    childrenKey: string = "children",
): ITreeItem<any>[] => {
  return arr.map((item, index) => {
    // Array of Arrays -> Group
    if (Array.isArray(item)) {
      return {
        [labelKey]: `Group${index + 1}`,
        [childrenKey]: reMapping(item, level + 1, labelKey, valueKey, childrenKey),
      };
    }
    // Object -> Check for children
    else if (typeof item === "object" && item !== null) {
      if (item[childrenKey] && Array.isArray(item[childrenKey])) {
        return {
          ...item,
          [childrenKey]: reMapping(item[childrenKey], 0, labelKey, valueKey, childrenKey),
        };
      }
      return item;
    }
    // Primitive -> Object
    else {
      return {[labelKey]: item, [valueKey]: item};
    }
  });
};

/**
 * Standard Normalizer: Ensures everything is an object { label, value }.
 */
export const mapping = (
    list: IListItem[],
    labelKey: string = "label",
    valueKey: string = "value",
    childrenKey: string = "children",
): Record<string, any>[] => {
  return list.map((item) => {
    // 1. Primitive -> Object
    if (typeof item === "string" || typeof item === "number") {
      return {[labelKey]: item.toString(), [valueKey]: item};
    }
    // 2. Object -> Recursion
    else if (typeof item === "object" && item !== null) {
      const newItem: any = {...item};

      if (childrenKey && Array.isArray(item[childrenKey])) {
        newItem[childrenKey] = mapping(
            item[childrenKey] as IListItem[],
            labelKey,
            valueKey,
            childrenKey,
        );
      }
      return newItem;
    }
    return item as Record<string, any>;
  });
};

/**
 * Converts flat data (with parentId) into a hierarchical Tree structure.
 */
export const buildTree = (
    data: Map<string | number, IListItem>,
    labelKey: string = "label",
    valueKey: string = "value",
    parentKey: any = "parentId",
    parentKeyValue: null | string | number = null,
): ITreeNode[] => {
  const fetchedData = Array.from(data.values());

  // 1. Process items for current parent
  const categorized: ITreeNode[] = fetchedData
      .filter((item) => typeof item == 'object' && item[parentKey] === parentKeyValue)
      .map((item) => {
        if(typeof item !== 'object'){
          return {
            key: item,
            label: item.toString(),
            data: item,
            // Web-specific helpers (ignored by Native if unused)
            className: `node-${item.toString()}`,
            id: item,
          }
        }
        const itemVal =  item[valueKey];
        const strVal = itemVal ? itemVal.toString() : "";

        return {
          key: itemVal,
          label: item[labelKey],
          data: item,
          // Web-specific helpers (ignored by Native if unused)
          className: `node-${strVal.split(".").join("_")}`,
          id: strVal,
          ...(item.selectable !== undefined && { selectable: item.selectable }),
          children: buildTree(data, labelKey, valueKey, parentKey, itemVal),
        };
      });

  // 2. Handle Orphans (Root level only)
  if (parentKeyValue === null) {
    const uncategorized: ITreeNode[] = fetchedData
        .filter((item) => typeof item == 'object' && item[parentKey] && !data.has(item[parentKey]))
        .map((item, index) => {
          if(typeof item !== 'object'){
            return {
              key: item,
              label: item.toString(),
              data: item,
              // Web-specific helpers (ignored by Native if unused)
              className: `node-${item.toString()}`,
              id: item,
            }
          }

          const itemVal = item[valueKey];
          const strVal = itemVal ? itemVal.toString() : "";

          return {
            key: `uncategorized-${index}`,
            label: item[labelKey],
            data: item,
            id: strVal,
            className: strVal,
            children: [],
          };
        });

    if (uncategorized.length > 0) {
      categorized.push({
        key: "uncategorized",
        label: "Uncategorized",
        children: uncategorized,
      });
    }
  }

  return categorized;
};
